class Solution:
    def maxArrayValue(self, nums: List[int]) -> int:
        n = len(nums)
        # Traverse from right to left
        for i in range(n - 2, -1, -1):
            # If current element is <= next element, merge them
            if nums[i] <= nums[i + 1]:
                nums[i] += nums[i + 1]
        # The maximum value is the maximum in the modified array
        return max(nums)
